UPDATE words SET example_en_2 = 'She rebutted his argument point by point.', example_ko_2 = '그녀는 그의 주장을 요점별로 반박했어요.', example_en_3 = 'How do you rebut a claim without new evidence?', example_ko_3 = '새 증거 없이 주장을 어떻게 반박하나요?', example_en_4 = 'He could not rebut the findings of the research.', example_ko_4 = '그는 연구 결과를 반박할 수 없었어요.', example_en_5 = 'A strong rebuttal requires logic, not just emotion.', example_ko_5 = '강력한 반박은 감정이 아닌 논리를 필요로 해요.' WHERE id = 'w_discussion_B2_01';

UPDATE words SET example_en_2 = 'Can you substantiate that claim with specific data?', example_ko_2 = '그 주장을 구체적인 데이터로 입증할 수 있나요?', example_en_3 = 'The new findings substantiate the earlier hypothesis.', example_ko_3 = '새 발견이 초기 가설을 입증해요.', example_en_4 = 'Please substantiate your position before we proceed.', example_ko_4 = '진행하기 전에 입장을 입증해 주세요.', example_en_5 = 'She struggled to substantiate her bold claim.', example_ko_5 = '그녀는 대담한 주장을 입증하는 데 애를 먹었어요.' WHERE id = 'w_discussion_B2_02';

UPDATE words SET example_en_2 = 'His critique of the theory was sharp and detailed.', example_ko_2 = '그 이론에 대한 그의 비평은 날카롭고 상세했어요.', example_en_3 = 'She offered a balanced critique of the proposal.', example_ko_3 = '그녀는 제안에 대한 균형 잡힌 비평을 제시했어요.', example_en_4 = 'A good critique is constructive, not destructive.', example_ko_4 = '좋은 비평은 파괴적이 아닌 건설적이에요.', example_en_5 = 'I found the critique of his argument quite compelling.', example_ko_5 = '그의 주장에 대한 비평이 꽤 설득력 있다고 생각했어요.' WHERE id = 'w_discussion_B2_03';

UPDATE words SET example_en_2 = 'The nuance of her argument was difficult to grasp.', example_ko_2 = '그녀 주장의 뉘앙스를 파악하기 어려웠어요.', example_en_3 = 'We must appreciate the nuance before making a judgment.', example_ko_3 = '판단하기 전에 뉘앙스를 이해해야 해요.', example_en_4 = 'There is an important nuance between these two terms.', example_ko_4 = '이 두 용어 사이에는 중요한 미묘한 차이가 있어요.', example_en_5 = 'Without nuance, the debate becomes too simplistic.', example_ko_5 = '뉘앙스 없이는 토론이 너무 단순해져요.' WHERE id = 'w_discussion_B2_04';

UPDATE words SET example_en_2 = 'Your argument rests on a shaky premise.', example_ko_2 = '당신의 주장은 불안정한 전제에 근거해 있어요.', example_en_3 = 'The entire debate was built on a false premise.', example_ko_3 = '토론 전체가 잘못된 전제 위에 구축됐어요.', example_en_4 = 'Let us first agree on the premise before arguing.', example_ko_4 = '논쟁하기 전에 전제에 먼저 동의해요.', example_en_5 = 'She challenged the premise of his opening statement.', example_ko_5 = '그녀는 그의 첫 발언의 전제에 이의를 제기했어요.' WHERE id = 'w_discussion_B2_05';

UPDATE words SET example_en_2 = 'That inference does not follow from the data.', example_ko_2 = '그 추론은 데이터에서 도출되지 않아요.', example_en_3 = 'Her inference was logical but too speculative.', example_ko_3 = '그녀의 추론은 논리적이었지만 너무 추측적이었어요.', example_en_4 = 'Drawing a correct inference is key to sound reasoning.', example_ko_4 = '올바른 추론을 이끌어내는 것이 건전한 논리의 핵심이에요.', example_en_5 = 'What inference can we make from these results?', example_ko_5 = '이 결과에서 어떤 추론을 할 수 있을까요?' WHERE id = 'w_discussion_B2_06';

UPDATE words SET example_en_2 = 'That reasoning contains a logical fallacy.', example_ko_2 = '그 논리에는 논리적 오류가 포함되어 있어요.', example_en_3 = 'Appealing to emotion without evidence is a fallacy.', example_ko_3 = '증거 없이 감정에 호소하는 건 오류예요.', example_en_4 = 'Spotting a fallacy in an argument is a useful skill.', example_ko_4 = '주장에서 오류를 발견하는 건 유용한 기술이에요.', example_en_5 = 'His argument collapsed because it was built on a fallacy.', example_ko_5 = '그의 주장은 오류 위에 구축됐기 때문에 무너졌어요.' WHERE id = 'w_discussion_B2_07';

UPDATE words SET example_en_2 = 'Political rhetoric often obscures the real issues.', example_ko_2 = '정치적 수사는 종종 진짜 문제를 모호하게 해요.', example_en_3 = 'His argument was all rhetoric and no substance.', example_ko_3 = '그의 주장은 전부 수사이고 실질이 없었어요.', example_en_4 = 'She used powerful rhetoric to win over the audience.', example_ko_4 = '그녀는 강력한 수사를 사용해 청중을 사로잡았어요.', example_en_5 = 'Good rhetoric should be supported by solid evidence.', example_ko_5 = '좋은 수사는 견고한 증거로 뒷받침되어야 해요.' WHERE id = 'w_discussion_B2_08';

UPDATE words SET example_en_2 = 'Confirmation bias makes us ignore opposing evidence.', example_ko_2 = '확증 편향은 반대되는 증거를 무시하게 만들어요.', example_en_3 = 'We all have biases that affect how we reason.', example_ko_3 = '우리 모두 논리에 영향을 미치는 편향이 있어요.', example_en_4 = 'Her analysis was free from personal bias.', example_ko_4 = '그녀의 분석은 개인적 편향에서 자유로웠어요.', example_en_5 = 'Being aware of your bias is the first step to fairness.', example_ko_5 = '자신의 편향을 인식하는 것이 공정함의 첫 단계예요.' WHERE id = 'w_discussion_B2_09';

UPDATE words SET example_en_2 = 'The report was praised for its objectivity.', example_ko_2 = '그 보고서는 객관성으로 칭찬을 받았어요.', example_en_3 = 'Maintaining objectivity during a debate is challenging.', example_ko_3 = '토론 중에 객관성을 유지하는 것은 어려워요.', example_en_4 = 'A good researcher values objectivity above all else.', example_ko_4 = '좋은 연구자는 무엇보다도 객관성을 중요하게 여겨요.', example_en_5 = 'She questioned his objectivity given his personal interest.', example_ko_5 = '그녀는 개인적 이해관계를 감안해 그의 객관성에 의문을 제기했어요.' WHERE id = 'w_discussion_B2_10';

UPDATE words SET example_en_2 = 'I concede that your point has some merit.', example_ko_2 = '당신의 요점에 일부 타당성이 있음을 인정해요.', example_en_3 = 'He finally conceded after reviewing the evidence.', example_ko_3 = '그는 증거를 검토한 후 마침내 인정했어요.', example_en_4 = 'Conceding a minor point can strengthen your overall case.', example_ko_4 = '사소한 요점을 인정하면 전체 논거를 강화할 수 있어요.', example_en_5 = 'She was reluctant to concede defeat in the debate.', example_ko_5 = '그녀는 토론에서 패배를 인정하기를 꺼려했어요.' WHERE id = 'w_discussion_B2_11';

UPDATE words SET example_en_2 = 'The contract language was deliberately ambiguous.', example_ko_2 = '계약서 언어는 의도적으로 모호했어요.', example_en_3 = 'His response was so ambiguous that no one understood it.', example_ko_3 = '그의 반응이 너무 모호해서 아무도 이해하지 못했어요.', example_en_4 = 'We need a clearer statement — this one is too ambiguous.', example_ko_4 = '더 명확한 발언이 필요해요 — 이건 너무 모호해요.', example_en_5 = 'Ambiguous language often leads to misunderstandings.', example_ko_5 = '모호한 언어는 종종 오해로 이어져요.' WHERE id = 'w_discussion_B2_12';

UPDATE words SET example_en_2 = 'Your conclusion contradicts your earlier statement.', example_ko_2 = '당신의 결론이 이전 발언과 모순돼요.', example_en_3 = 'The new data contradicts everything we assumed.', example_ko_3 = '새 데이터가 우리가 가정한 모든 것과 모순돼요.', example_en_4 = 'She was careful not to contradict herself.', example_ko_4 = '그녀는 스스로 모순되지 않도록 주의했어요.', example_en_5 = 'It is a problem when the facts contradict the theory.', example_ko_5 = '사실이 이론과 모순될 때 문제가 돼요.' WHERE id = 'w_discussion_B2_13';

UPDATE words SET example_en_2 = 'He asserted that the policy was unconstitutional.', example_ko_2 = '그는 그 정책이 위헌이라고 주장했어요.', example_en_3 = 'She asserts that the research is biased.', example_ko_3 = '그녀는 연구가 편향되어 있다고 단언해요.', example_en_4 = 'You cannot simply assert something without proof.', example_ko_4 = '증거 없이 단순히 무언가를 주장할 수는 없어요.', example_en_5 = 'The lawyer asserted the innocence of her client.', example_ko_5 = '변호사는 자신의 의뢰인의 무고함을 주장했어요.' WHERE id = 'w_discussion_B2_14';

UPDATE words SET example_en_2 = 'What is the underlying assumption here?', example_ko_2 = '여기서 근본적인 가정이 뭔가요?', example_en_3 = 'The underlying tension was never addressed.', example_ko_3 = '근본적인 긴장감은 한 번도 다뤄지지 않았어요.', example_en_4 = 'There is an underlying problem that we are ignoring.', example_ko_4 = '우리가 무시하고 있는 근본적인 문제가 있어요.', example_en_5 = 'She identified the underlying flaw in his reasoning.', example_ko_5 = '그녀는 그의 논리에서 근본적인 결함을 찾아냈어요.' WHERE id = 'w_discussion_B2_15';

UPDATE words SET example_en_2 = 'Have you considered all the implications of this decision?', example_ko_2 = '이 결정의 모든 함의를 고려해봤나요?', example_en_3 = 'The implication was clear — someone had to take responsibility.', example_ko_3 = '함의는 명확했어요 — 누군가가 책임을 져야 했어요.', example_en_4 = 'Her words had serious implications for the team.', example_ko_4 = '그녀의 말은 팀에게 중대한 함의를 가졌어요.', example_en_5 = 'The full implications of the research are not yet clear.', example_ko_5 = '연구의 전체 함의는 아직 명확하지 않아요.' WHERE id = 'w_discussion_B2_16';

UPDATE words SET example_en_2 = 'Her argument was coherent from start to finish.', example_ko_2 = '그녀의 주장은 처음부터 끝까지 일관성이 있었어요.', example_en_3 = 'Without a coherent structure, the essay was hard to follow.', example_ko_3 = '일관된 구조가 없으니 에세이를 따라가기 어려웠어요.', example_en_4 = 'A coherent argument is easier for others to evaluate.', example_ko_4 = '일관성 있는 주장은 다른 사람들이 평가하기 더 쉬워요.', example_en_5 = 'Please reorganize your thoughts into a more coherent form.', example_ko_5 = '생각을 더 일관된 형태로 재구성해 주세요.' WHERE id = 'w_discussion_B2_17';

UPDATE words SET example_en_2 = 'We need to scrutinize each assumption in this theory.', example_ko_2 = '이 이론의 각 가정을 면밀히 검토해야 해요.', example_en_3 = 'Her credentials were scrutinized before she was hired.', example_ko_3 = '그녀의 자격증은 채용 전에 면밀히 검토됐어요.', example_en_4 = 'Scrutinizing the evidence helped reveal the truth.', example_ko_4 = '증거를 면밀히 검토하는 것이 진실을 밝히는 데 도움이 됐어요.', example_en_5 = 'All claims should be scrutinized before being accepted.', example_ko_5 = '모든 주장은 받아들이기 전에 면밀히 검토되어야 해요.' WHERE id = 'w_discussion_B2_18';

UPDATE words SET example_en_2 = 'We need to refine our argument before presenting it.', example_ko_2 = '발표 전에 주장을 다듬어야 해요.', example_en_3 = 'She refined her theory based on new feedback.', example_ko_3 = '그녀는 새 피드백을 바탕으로 이론을 다듬었어요.', example_en_4 = 'Good writing requires constantly refining your ideas.', example_ko_4 = '좋은 글쓰기는 아이디어를 끊임없이 다듬는 것이 필요해요.', example_en_5 = 'After several revisions, the argument was greatly refined.', example_ko_5 = '여러 번 수정 끝에 주장이 크게 다듬어졌어요.' WHERE id = 'w_discussion_B2_19';

UPDATE words SET example_en_2 = 'There is a discrepancy between the two reports.', example_ko_2 = '두 보고서 사이에 불일치가 있어요.', example_en_3 = 'Please explain the discrepancy in your numbers.', example_ko_3 = '당신의 숫자에서 나타나는 불일치를 설명해 주세요.', example_en_4 = 'The discrepancy between theory and practice was clear.', example_ko_4 = '이론과 실제 사이의 불일치가 명확했어요.', example_en_5 = 'We need to resolve this discrepancy before going further.', example_ko_5 = '더 나아가기 전에 이 불일치를 해결해야 해요.' WHERE id = 'w_discussion_B2_20';

UPDATE words SET example_en_2 = 'She advocates for a more inclusive approach.', example_ko_2 = '그녀는 더 포용적인 접근법을 옹호해요.', example_en_3 = 'He has long advocated for policy reform.', example_ko_3 = '그는 오랫동안 정책 개혁을 옹호해왔어요.', example_en_4 = 'I advocate for giving everyone an equal voice.', example_ko_4 = '모두에게 동등한 발언권을 주는 것을 지지해요.', example_en_5 = 'The organization advocates for environmental protection.', example_ko_5 = '그 단체는 환경 보호를 옹호해요.' WHERE id = 'w_discussion_B2_21';

UPDATE words SET example_en_2 = 'The inconsistency in her argument weakened her case.', example_ko_2 = '그녀의 주장에서의 비일관성이 논거를 약화시켰어요.', example_en_3 = 'Please address the inconsistency I pointed out earlier.', example_ko_3 = '제가 앞서 지적한 비일관성을 다뤄 주세요.', example_en_4 = 'There is a clear inconsistency between his words and actions.', example_ko_4 = '그의 말과 행동 사이에 명확한 비일관성이 있어요.', example_en_5 = 'Avoiding inconsistency is essential in academic writing.', example_ko_5 = '학술 글쓰기에서 비일관성을 피하는 것이 필수적이에요.' WHERE id = 'w_discussion_B2_22';

UPDATE words SET example_en_2 = 'She presented a compelling case for reform.', example_ko_2 = '그녀는 개혁을 위한 설득력 있는 논거를 제시했어요.', example_en_3 = 'The most compelling argument came at the end.', example_ko_3 = '가장 설득력 있는 주장이 마지막에 나왔어요.', example_en_4 = 'I find her evidence very compelling.', example_ko_4 = '그녀의 증거가 매우 설득력 있다고 생각해요.', example_en_5 = 'A compelling argument needs both logic and evidence.', example_ko_5 = '설득력 있는 주장은 논리와 증거 모두를 필요로 해요.' WHERE id = 'w_discussion_B2_23';

UPDATE words SET example_en_2 = 'What steps can we take to mitigate the damage?', example_ko_2 = '피해를 완화하기 위해 어떤 조치를 취할 수 있을까요?', example_en_3 = 'The policy was designed to mitigate the effects of inflation.', example_ko_3 = '그 정책은 인플레이션의 영향을 완화하도록 설계됐어요.', example_en_4 = 'Early action helps mitigate long-term consequences.', example_ko_4 = '초기 조치는 장기적인 결과를 완화하는 데 도움이 돼요.', example_en_5 = 'Is there anything we can do to mitigate the conflict?', example_ko_5 = '갈등을 완화하기 위해 할 수 있는 것이 있을까요?' WHERE id = 'w_discussion_B2_24';

UPDATE words SET example_en_2 = 'Social media tends to polarize public opinion.', example_ko_2 = '소셜 미디어는 여론을 양극화시키는 경향이 있어요.', example_en_3 = 'The debate polarized the team into two camps.', example_ko_3 = '토론이 팀을 두 진영으로 양극화시켰어요.', example_en_4 = 'Polarizing language makes compromise harder.', example_ko_4 = '양극화하는 언어는 타협을 더 어렵게 만들어요.', example_en_5 = 'He worried that his comments would further polarize the group.', example_ko_5 = '그는 자신의 발언이 그룹을 더 양극화시킬까봐 걱정했어요.' WHERE id = 'w_discussion_B2_25';

UPDATE words SET example_en_2 = 'The agreement is still provisional and may change.', example_ko_2 = '합의는 아직 잠정적이고 바뀔 수 있어요.', example_en_3 = 'We reached a provisional solution pending more information.', example_ko_3 = '더 많은 정보를 기다리며 잠정적인 해결책에 도달했어요.', example_en_4 = 'This is a provisional arrangement, not a final decision.', example_ko_4 = '이건 최종 결정이 아닌 잠정적인 합의예요.', example_en_5 = 'A provisional agreement was signed until further review.', example_ko_5 = '추가 검토가 있을 때까지 잠정적인 합의가 체결됐어요.' WHERE id = 'w_discussion_B2_26';

UPDATE words SET example_en_2 = 'Please be explicit about what you are asking for.', example_ko_2 = '요청하는 것이 무엇인지 명확하게 말씀해 주세요.', example_en_3 = 'The guidelines were explicit about the expected behavior.', example_ko_3 = '지침은 기대되는 행동에 대해 명시적이었어요.', example_en_4 = 'He was explicit in his support for the plan.', example_ko_4 = '그는 그 계획에 대한 지지를 명시적으로 표현했어요.', example_en_5 = 'An explicit statement avoids unnecessary confusion.', example_ko_5 = '명시적인 발언은 불필요한 혼란을 피하게 해요.' WHERE id = 'w_discussion_B2_27';

UPDATE words SET example_en_2 = 'Critical thinking is essential for good decision-making.', example_ko_2 = '비판적 사고는 좋은 의사결정에 필수적이에요.', example_en_3 = 'He was critical of the way the decision was made.', example_ko_3 = '그는 결정이 내려진 방식에 비판적이었어요.', example_en_4 = 'A critical review helped improve the final proposal.', example_ko_4 = '비판적 검토가 최종 제안을 개선하는 데 도움이 됐어요.', example_en_5 = 'Being critical does not mean being negative — it means being thoughtful.', example_ko_5 = '비판적이라는 건 부정적이라는 게 아니라 신중하다는 뜻이에요.' WHERE id = 'w_discussion_B2_28';

UPDATE words SET example_en_2 = 'It is easy to oversimplify a complex social problem.', example_ko_2 = '복잡한 사회 문제를 지나치게 단순화하기 쉬워요.', example_en_3 = 'He oversimplified the situation by ignoring key details.', example_ko_3 = '그는 핵심 세부 사항을 무시함으로써 상황을 지나치게 단순화했어요.', example_en_4 = 'Avoid oversimplifying when the issue is genuinely complex.', example_ko_4 = '문제가 진정으로 복잡할 때는 지나치게 단순화하지 마세요.', example_en_5 = 'Her analysis oversimplified the relationship between the two factors.', example_ko_5 = '그녀의 분석은 두 요인 사이의 관계를 지나치게 단순화했어요.' WHERE id = 'w_discussion_B2_29';

UPDATE words SET example_en_2 = 'In a hypothetical scenario, what would you choose?', example_ko_2 = '가상의 시나리오에서 무엇을 선택하시겠어요?', example_en_3 = 'She posed a hypothetical question to test his reasoning.', example_ko_3 = '그녀는 그의 논리를 시험하기 위해 가상의 질문을 제시했어요.', example_en_4 = 'His argument was based on a hypothetical situation.', example_ko_4 = '그의 주장은 가상의 상황에 근거했어요.', example_en_5 = 'Hypothetical thinking is useful in philosophical debate.', example_ko_5 = '가상적 사고는 철학적 토론에 유용해요.' WHERE id = 'w_discussion_B2_30';

UPDATE words SET example_en_2 = 'The theory lacks empirical support.', example_ko_2 = '그 이론에는 경험적 뒷받침이 부족해요.', example_en_3 = 'Empirical research is essential in science.', example_ko_3 = '경험적 연구는 과학에서 필수적이에요.', example_en_4 = 'Her empirical findings challenged the prevailing theory.', example_ko_4 = '그녀의 경험적 발견이 지배적인 이론에 도전했어요.', example_en_5 = 'We need empirical data, not just theoretical models.', example_ko_5 = '이론적 모델만이 아닌 경험적 데이터가 필요해요.' WHERE id = 'w_discussion_B2_31';

UPDATE words SET example_en_2 = 'We need a shared framework for evaluating ideas.', example_ko_2 = '아이디어를 평가하기 위한 공유된 틀이 필요해요.', example_en_3 = 'Her framework for analysis was clear and practical.', example_ko_3 = '그녀의 분석 틀은 명확하고 실용적이었어요.', example_en_4 = 'Without a framework, the discussion became disorganized.', example_ko_4 = '틀이 없으면 토론이 체계를 잃게 돼요.', example_en_5 = 'This conceptual framework helps organize our thinking.', example_ko_5 = '이 개념적 틀은 우리의 사고를 조직하는 데 도움이 돼요.' WHERE id = 'w_discussion_B2_32';

UPDATE words SET example_en_2 = 'Making a concession helped to advance the negotiation.', example_ko_2 = '양보를 하는 것이 협상을 진전시키는 데 도움이 됐어요.', example_en_3 = 'His concession on the minor point was seen as a sign of good faith.', example_ko_3 = '사소한 부분에서의 그의 양보는 선의의 표시로 여겨졌어요.', example_en_4 = 'A well-timed concession can change the tone of a debate.', example_ko_4 = '적절한 타이밍의 양보는 토론의 분위기를 바꿀 수 있어요.', example_en_5 = 'She made a concession but held firm on her main position.', example_ko_5 = '그녀는 양보했지만 주요 입장은 굳건하게 유지했어요.' WHERE id = 'w_discussion_B2_33';

UPDATE words SET example_en_2 = 'Our opinions diverge on almost every major issue.', example_ko_2 = '우리의 의견은 거의 모든 주요 문제에서 갈려요.', example_en_3 = 'The two schools of thought diverge sharply here.', example_ko_3 = '두 사상 학파는 여기서 크게 갈려요.', example_en_4 = 'Their views diverged after reviewing different sources.', example_ko_4 = '서로 다른 자료를 검토한 후 그들의 견해가 갈렸어요.', example_en_5 = 'It is fine for perspectives to diverge — that is the nature of debate.', example_ko_5 = '관점이 갈리는 건 괜찮아요 — 그게 토론의 본질이에요.' WHERE id = 'w_discussion_B2_34';

UPDATE words SET example_en_2 = 'We need to build consensus before moving forward.', example_ko_2 = '앞으로 나아가기 전에 합의를 구축해야 해요.', example_en_3 = 'There is a growing consensus that change is needed.', example_ko_3 = '변화가 필요하다는 합의가 커지고 있어요.', example_en_4 = 'The group reached consensus after a long discussion.', example_ko_4 = '그룹은 긴 토론 끝에 합의에 이르렀어요.', example_en_5 = 'A lack of consensus makes decision-making very difficult.', example_ko_5 = '합의의 부재는 의사결정을 매우 어렵게 만들어요.' WHERE id = 'w_discussion_B2_35';

