UPDATE words SET example_en_2 = 'A hermeneutic analysis reveals layers of meaning in the text.', example_ko_2 = '해석학적 분석은 텍스트 속의 의미 층위를 드러내요.', example_en_3 = 'Her hermeneutic approach considered the cultural context deeply.', example_ko_3 = '그녀의 해석학적 접근법은 문화적 맥락을 깊이 고려했어요.', example_en_4 = 'The hermeneutic circle describes how parts and wholes shape each other.', example_ko_4 = '해석학적 순환은 부분과 전체가 서로 어떻게 형성하는지를 설명해요.', example_en_5 = 'Legal hermeneutics applies interpretive theory to the reading of statutes.', example_ko_5 = '법적 해석학은 해석 이론을 법령 읽기에 적용해요.' WHERE id = 'w_discussion_C2_01';

UPDATE words SET example_en_2 = 'The dialogue ended in aporia, with no resolution in sight.', example_ko_2 = '대화는 어떤 해결도 보이지 않는 아포리아로 끝났어요.', example_en_3 = 'Reaching aporia is the beginning of genuine inquiry, not its failure.', example_ko_3 = '아포리아에 이르는 것은 진정한 탐구의 실패가 아니라 시작이에요.', example_en_4 = 'The philosopher embraced aporia as a sign that the question was worth pursuing.', example_ko_4 = '철학자는 아포리아를 그 질문이 추구할 가치가 있다는 표시로 받아들였어요.', example_en_5 = 'She led the seminar into productive aporia by challenging every assumption.', example_ko_5 = '그녀는 모든 가정에 이의를 제기함으로써 세미나를 생산적인 아포리아로 이끌었어요.' WHERE id = 'w_discussion_C2_02';

UPDATE words SET example_en_2 = 'Deconstruction reveals how texts undermine their own claimed meanings.', example_ko_2 = '해체주의는 텍스트가 어떻게 자신이 주장하는 의미를 스스로 훼손하는지를 드러내요.', example_en_3 = 'She applied deconstruction to expose the ideology hidden in the text.', example_ko_3 = '그녀는 해체주의를 적용해 텍스트에 숨겨진 이념을 노출했어요.', example_en_4 = 'Deconstruction does not destroy meaning but multiplies its possibilities.', example_ko_4 = '해체주의는 의미를 파괴하는 것이 아니라 가능성을 늘려요.', example_en_5 = 'Critics of deconstruction argue it leads to interpretive relativism.', example_ko_5 = '해체주의 비판가들은 그것이 해석적 상대주의로 이어진다고 주장해요.' WHERE id = 'w_discussion_C2_03';

UPDATE words SET example_en_2 = 'Logocentrism elevates rational argument above other modes of expression.', example_ko_2 = '로고스 중심주의는 다른 표현 방식보다 합리적 논쟁을 높이 평가해요.', example_en_3 = 'Derrida''s critique of logocentrism transformed literary theory.', example_ko_3 = '데리다의 로고스 중심주의 비판은 문학 이론을 변혁시켰어요.', example_en_4 = 'Logocentrism assumes that spoken language is closer to truth than writing.', example_ko_4 = '로고스 중심주의는 구어가 문자보다 진리에 더 가깝다고 가정해요.', example_en_5 = 'Her paper challenged the logocentrism embedded in Western philosophy.', example_ko_5 = '그녀의 논문은 서양 철학에 내재된 로고스 중심주의에 이의를 제기했어요.' WHERE id = 'w_discussion_C2_04';

UPDATE words SET example_en_2 = 'Intersubjectivity is the foundation of all cooperative endeavor.', example_ko_2 = '상호주관성은 모든 협력적 노력의 토대예요.', example_en_3 = 'Without intersubjectivity, genuine dialogue is impossible.', example_ko_3 = '상호주관성 없이는 진정한 대화가 불가능해요.', example_en_4 = 'He explored intersubjectivity as the basis for ethical responsibility.', example_ko_4 = '그는 상호주관성을 윤리적 책임의 토대로 탐구했어요.', example_en_5 = 'The concept of intersubjectivity bridges individual and collective understanding.', example_ko_5 = '상호주관성 개념은 개인적 이해와 집단적 이해를 연결해요.' WHERE id = 'w_discussion_C2_05';

UPDATE words SET example_en_2 = 'The discourse of power shapes who gets to speak.', example_ko_2 = '권력의 담론은 누가 발언할 수 있는지를 형성해요.', example_en_3 = 'Academic discourse has its own conventions and assumptions.', example_ko_3 = '학술 담론은 고유의 관행과 가정을 가지고 있어요.', example_en_4 = 'She analyzed how political discourse frames immigration debates.', example_ko_4 = '그녀는 정치 담론이 이민 토론을 어떻게 구성하는지 분석했어요.', example_en_5 = 'The shift in public discourse reflected deeper cultural changes.', example_ko_5 = '공공 담론의 전환은 더 깊은 문화적 변화를 반영했어요.' WHERE id = 'w_discussion_C2_06';

UPDATE words SET example_en_2 = 'Critical pedagogy emphasizes praxis over passive learning.', example_ko_2 = '비판적 교육학은 수동적 학습보다 실천을 강조해요.', example_en_3 = 'Praxis involves transforming knowledge into meaningful action.', example_ko_3 = '실천은 지식을 의미 있는 행동으로 변환하는 것을 포함해요.', example_en_4 = 'Without praxis, theory risks becoming mere abstraction.', example_ko_4 = '실천 없이는 이론이 단순한 추상으로 전락할 위험이 있어요.', example_en_5 = 'The seminar moved from abstract theory to grounded praxis.', example_ko_5 = '세미나는 추상적 이론에서 근거 있는 실천으로 나아갔어요.' WHERE id = 'w_discussion_C2_07';

UPDATE words SET example_en_2 = 'The debate raised ontological questions about the nature of identity.', example_ko_2 = '그 토론은 정체성의 본질에 관한 존재론적 질문을 제기했어요.', example_en_3 = 'Ontological commitments shape what we count as real.', example_ko_3 = '존재론적 전제들은 우리가 무엇을 실재로 여기는지를 형성해요.', example_en_4 = 'Her ontological argument challenged the materialist framework.', example_ko_4 = '그녀의 존재론적 주장은 유물론적 틀에 이의를 제기했어요.', example_en_5 = 'The ontological gap between subject and object is a perennial philosophical problem.', example_ko_5 = '주체와 객체 사이의 존재론적 간극은 영원한 철학적 문제예요.' WHERE id = 'w_discussion_C2_08';

UPDATE words SET example_en_2 = 'This case is paradigmatic of institutional failure.', example_ko_2 = '이 사례는 제도적 실패의 전형적인 예시예요.', example_en_3 = 'Kuhn described scientific revolutions as paradigmatic shifts.', example_ko_3 = '쿤은 과학 혁명을 패러다임적 전환으로 묘사했어요.', example_en_4 = 'A paradigmatic example simplifies complex theory for teaching.', example_ko_4 = '전형적인 예시는 교육을 위해 복잡한 이론을 단순화해요.', example_en_5 = 'Her paper offered a paradigmatic analysis of the genre.', example_ko_5 = '그녀의 논문은 그 장르에 대한 전형적인 분석을 제공했어요.' WHERE id = 'w_discussion_C2_09';

UPDATE words SET example_en_2 = 'The phenomenological method focuses on first-person experience.', example_ko_2 = '현상학적 방법은 1인칭 경험에 집중해요.', example_en_3 = 'She conducted a phenomenological study of grief.', example_ko_3 = '그녀는 슬픔에 대한 현상학적 연구를 수행했어요.', example_en_4 = 'The phenomenological approach reveals what is usually taken for granted.', example_ko_4 = '현상학적 접근법은 대개 당연하게 여겨지는 것을 드러내요.', example_en_5 = 'Husserl pioneered the phenomenological reduction as a philosophical method.', example_ko_5 = '후설은 현상학적 환원을 철학적 방법으로 선구적으로 제시했어요.' WHERE id = 'w_discussion_C2_10';

UPDATE words SET example_en_2 = 'A teleological explanation explains things by their ends or purposes.', example_ko_2 = '목적론적 설명은 사물의 목적이나 끝에 의해 설명해요.', example_en_3 = 'She used a teleological framework to interpret historical change.', example_ko_3 = '그녀는 역사적 변화를 해석하기 위해 목적론적 틀을 사용했어요.', example_en_4 = 'Critics argue that teleological reasoning cannot avoid circularity.', example_ko_4 = '비판가들은 목적론적 추론이 순환성을 피할 수 없다고 주장해요.', example_en_5 = 'Teleological ethics judges actions by their outcomes, not intentions.', example_ko_5 = '목적론적 윤리는 의도가 아닌 결과로 행동을 판단해요.' WHERE id = 'w_discussion_C2_11';

UPDATE words SET example_en_2 = 'The dialectical method moves through contradiction to resolution.', example_ko_2 = '변증법적 방법은 모순을 거쳐 해결로 나아가요.', example_en_3 = 'A dialectical reading of history sees conflict as the engine of change.', example_ko_3 = '역사에 대한 변증법적 독해는 갈등을 변화의 동력으로 봐요.', example_en_4 = 'He applied a dialectical framework to analyze political discourse.', example_ko_4 = '그는 정치 담론을 분석하기 위해 변증법적 틀을 적용했어요.', example_en_5 = 'The dialectical tension between freedom and equality drives political philosophy.', example_ko_5 = '자유와 평등 사이의 변증법적 긴장감이 정치철학을 이끌어요.' WHERE id = 'w_discussion_C2_12';

UPDATE words SET example_en_2 = 'The epistemological challenge is to distinguish knowledge from belief.', example_ko_2 = '인식론적 도전은 지식과 믿음을 구별하는 것이에요.', example_en_3 = 'This epistemological debate has persisted since the ancient Greeks.', example_ko_3 = '이 인식론적 토론은 고대 그리스 이래로 지속돼왔어요.', example_en_4 = 'She explored the epistemological foundations of scientific inquiry.', example_ko_4 = '그녀는 과학적 탐구의 인식론적 토대를 탐구했어요.', example_en_5 = 'The argument raises serious epistemological doubts about the method.', example_ko_5 = '그 주장은 방법에 관한 심각한 인식론적 의심을 제기해요.' WHERE id = 'w_discussion_C2_13';

UPDATE words SET example_en_2 = 'Science and art may be incommensurable in their goals.', example_ko_2 = '과학과 예술은 목표에서 비교 불가능할 수도 있어요.', example_en_3 = 'The two paradigms are incommensurable and cannot be directly compared.', example_ko_3 = '두 패러다임은 공약 불가능하여 직접 비교할 수 없어요.', example_en_4 = 'Their values were incommensurable, making compromise impossible.', example_ko_4 = '그들의 가치는 비교 불가능해서 타협이 불가능했어요.', example_en_5 = 'Incommensurable positions require a new framework to bridge them.', example_ko_5 = '공약 불가능한 입장들은 연결을 위한 새로운 틀이 필요해요.' WHERE id = 'w_discussion_C2_14';

UPDATE words SET example_en_2 = 'A metatheory examines the assumptions of a lower-level theory.', example_ko_2 = '메타이론은 하위 수준 이론의 가정들을 검토해요.', example_en_3 = 'She developed a metatheory that unified several competing frameworks.', example_ko_3 = '그녀는 여러 경쟁 틀을 통합하는 메타이론을 개발했어요.', example_en_4 = 'Metatheory does not answer questions but clarifies how to ask them.', example_ko_4 = '메타이론은 질문에 답하는 것이 아니라 어떻게 질문할지를 명확히 해요.', example_en_5 = 'His metatheory of ethics assessed the criteria used by different moral theories.', example_ko_5 = '그의 윤리 메타이론은 다른 도덕 이론들이 사용하는 기준을 평가했어요.' WHERE id = 'w_discussion_C2_15';

UPDATE words SET example_en_2 = 'Her final essay was the apotheosis of her academic career.', example_ko_2 = '그녀의 마지막 에세이는 그녀의 학문적 경력의 절정이었어요.', example_en_3 = 'The debate reached its apotheosis in the final hour.', example_ko_3 = '토론은 마지막 시간에 절정에 달했어요.', example_en_4 = 'His speech represented the apotheosis of rhetorical skill.', example_ko_4 = '그의 연설은 수사 기술의 절정을 대표했어요.', example_en_5 = 'That moment was the apotheosis of years of intellectual preparation.', example_ko_5 = '그 순간은 수년간의 지적 준비의 절정이었어요.' WHERE id = 'w_discussion_C2_16';

UPDATE words SET example_en_2 = 'She was known for her heterodox views on economic theory.', example_ko_2 = '그녀는 경제 이론에 관한 비정통적인 견해로 알려져 있었어요.', example_en_3 = 'Heterodox thinkers often challenge prevailing assumptions.', example_ko_3 = '비정통적 사상가들은 종종 지배적인 가정에 도전해요.', example_en_4 = 'His heterodox stance was initially dismissed but later validated.', example_ko_4 = '그의 비정통적인 입장은 처음에 묵살됐지만 나중에 입증됐어요.', example_en_5 = 'Heterodox approaches are often the source of genuine innovation.', example_ko_5 = '비정통적 접근법은 종종 진정한 혁신의 원천이에요.' WHERE id = 'w_discussion_C2_17';

UPDATE words SET example_en_2 = 'He treated the conclusion as apodictic, but it was not.', example_ko_2 = '그는 결론을 자명한 것으로 다뤘지만 그렇지 않았어요.', example_en_3 = 'Apodictic certainty is rare even in mathematics.', example_ko_3 = '자명한 확실성은 수학에서도 드물어요.', example_en_4 = 'She was careful not to make apodictic claims in contested territory.', example_ko_4 = '그녀는 논쟁적인 영역에서 자명한 주장을 하지 않도록 주의했어요.', example_en_5 = 'An apodictic statement requires universal and necessary truth.', example_ko_5 = '자명한 진술은 보편적이고 필연적인 진리를 필요로 해요.' WHERE id = 'w_discussion_C2_18';

UPDATE words SET example_en_2 = 'A semiotic reading of the advertisement reveals cultural assumptions.', example_ko_2 = '광고의 기호학적 독해는 문화적 가정들을 드러내요.', example_en_3 = 'She applied semiotic theory to the study of political symbols.', example_ko_3 = '그녀는 기호학 이론을 정치적 상징 연구에 적용했어요.', example_en_4 = 'The semiotic approach treats language as a system of signs.', example_ko_4 = '기호학적 접근법은 언어를 기호 체계로 다루어요.', example_en_5 = 'Semiotic analysis can reveal ideological meanings beneath the surface.', example_ko_5 = '기호학적 분석은 표면 아래의 이념적 의미를 드러낼 수 있어요.' WHERE id = 'w_discussion_C2_19';

UPDATE words SET example_en_2 = 'A defeasible argument is rational but open to revision.', example_ko_2 = '논박 가능한 주장은 합리적이지만 수정에 열려 있어요.', example_en_3 = 'Most legal reasoning is defeasible rather than conclusive.', example_ko_3 = '대부분의 법적 추론은 결정적이기보다 논박 가능해요.', example_en_4 = 'Her argument was defeasible but the best available given the evidence.', example_ko_4 = '그녀의 주장은 논박 가능했지만 증거를 감안하면 최선이었어요.', example_en_5 = 'Defeasible conclusions should be held with appropriate humility.', example_ko_5 = '논박 가능한 결론들은 적절한 겸손함으로 유지되어야 해요.' WHERE id = 'w_discussion_C2_20';

UPDATE words SET example_en_2 = 'The polysemy of this word makes translation difficult.', example_ko_2 = '이 단어의 다의성은 번역을 어렵게 만들어요.', example_en_3 = 'Polysemy often causes miscommunication in cross-cultural debate.', example_ko_3 = '다의성은 종종 문화 간 토론에서 오해를 일으켜요.', example_en_4 = 'Legal language aims to minimize polysemy through precise definitions.', example_ko_4 = '법적 언어는 정밀한 정의를 통해 다의성을 최소화하려 해요.', example_en_5 = 'She exploited the polysemy of the term to shift the argument.', example_ko_5 = '그녀는 논쟁을 전환하기 위해 용어의 다의성을 이용했어요.' WHERE id = 'w_discussion_C2_21';

UPDATE words SET example_en_2 = 'The critique is immanent to the tradition it challenges.', example_ko_2 = '그 비판은 그것이 도전하는 전통에 내재적이에요.', example_en_3 = 'An immanent critique works from within the system it questions.', example_ko_3 = '내재적 비판은 그것이 의문시하는 시스템 내부에서 작동해요.', example_en_4 = 'She offered an immanent critique rather than an external attack.', example_ko_4 = '그녀는 외부 공격이 아닌 내재적 비판을 제시했어요.', example_en_5 = 'An immanent approach reveals the internal contradictions of a theory.', example_ko_5 = '내재적 접근법은 이론의 내부 모순을 드러내요.' WHERE id = 'w_discussion_C2_22';

UPDATE words SET example_en_2 = 'The seminar offered a detailed exegesis of the key passage.', example_ko_2 = '세미나는 핵심 구절에 대한 상세한 주석을 제공했어요.', example_en_3 = 'Biblical exegesis requires knowledge of ancient languages.', example_ko_3 = '성경 주석은 고대 언어에 대한 지식이 필요해요.', example_en_4 = 'Her exegesis of the text revealed meanings no one had seen before.', example_ko_4 = '텍스트에 대한 그녀의 주석은 이전에 아무도 보지 못한 의미를 드러냈어요.', example_en_5 = 'He provided a careful exegesis before offering his own interpretation.', example_ko_5 = '그는 자신의 해석을 제시하기 전에 신중한 주석을 제공했어요.' WHERE id = 'w_discussion_C2_23';

UPDATE words SET example_en_2 = 'The book begins with prolegomena on the method of inquiry.', example_ko_2 = '그 책은 탐구 방법에 대한 예비적 고찰로 시작해요.', example_en_3 = 'The prolegomena to the theory occupy the first three chapters.', example_ko_3 = '이론의 서론이 첫 세 챕터를 차지해요.', example_en_4 = 'Without prolegomena, readers may miss the framework of the argument.', example_ko_4 = '서론이 없으면 독자들이 주장의 틀을 놓칠 수 있어요.', example_en_5 = 'She wrote the prolegomena last, after the argument was fully developed.', example_ko_5 = '그녀는 주장이 완전히 전개된 후에 서론을 마지막으로 썼어요.' WHERE id = 'w_discussion_C2_24';

UPDATE words SET example_en_2 = 'Kant identified an antinomy in the concept of freedom.', example_ko_2 = '칸트는 자유 개념에서 이율배반을 발견했어요.', example_en_3 = 'The antinomy between determinism and free will remains unresolved.', example_ko_3 = '결정론과 자유의지 사이의 이율배반은 여전히 해결되지 않았어요.', example_en_4 = 'Her essay explored the antinomy at the heart of liberal democracy.', example_ko_4 = '그녀의 에세이는 자유민주주의 핵심의 이율배반을 탐구했어요.', example_en_5 = 'The antinomy revealed that both positions lead to contradiction.', example_ko_5 = '이율배반은 두 입장 모두 모순으로 이어진다는 것을 드러냈어요.' WHERE id = 'w_discussion_C2_25';

UPDATE words SET example_en_2 = 'Explaining qualia remains one of philosophy''s hardest problems.', example_ko_2 = '감각질을 설명하는 것은 여전히 철학의 가장 어려운 문제 중 하나예요.', example_en_3 = 'What does red look like to you? That is the question of qualia.', example_ko_3 = '빨강이 당신에게 어떻게 보이나요? 그게 감각질의 질문이에요.', example_en_4 = 'Physicalists argue that qualia can be fully explained by brain states.', example_ko_4 = '물리주의자들은 감각질이 뇌 상태로 완전히 설명될 수 있다고 주장해요.', example_en_5 = 'The debate over qualia cuts to the heart of the mind-body problem.', example_ko_5 = '감각질에 관한 토론은 심신 문제의 핵심을 다루어요.' WHERE id = 'w_discussion_C2_26';

UPDATE words SET example_en_2 = 'Recognizing alterity is the foundation of ethical responsibility.', example_ko_2 = '타자성을 인식하는 것이 윤리적 책임의 토대예요.', example_en_3 = 'She explored alterity as what makes genuine dialogue possible.', example_ko_3 = '그녀는 타자성을 진정한 대화를 가능하게 하는 것으로 탐구했어요.', example_en_4 = 'Ignoring alterity leads to colonizing others with our own assumptions.', example_ko_4 = '타자성을 무시하면 우리의 가정으로 다른 사람들을 식민화하게 돼요.', example_en_5 = 'Levinas placed alterity at the center of his ethical philosophy.', example_ko_5 = '레비나스는 타자성을 자신의 윤리 철학의 중심에 두었어요.' WHERE id = 'w_discussion_C2_27';

UPDATE words SET example_en_2 = 'The reification of social norms makes them seem natural and fixed.', example_ko_2 = '사회 규범의 물화는 그것들을 자연스럽고 고정된 것처럼 보이게 해요.', example_en_3 = 'She analyzed the reification of gender in media representation.', example_ko_3 = '그녀는 미디어 표현에서 젠더의 물화를 분석했어요.', example_en_4 = 'The reification of market value distorts how we see human relationships.', example_ko_4 = '시장 가치의 물화는 우리가 인간 관계를 보는 방식을 왜곡해요.', example_en_5 = 'Critical theory seeks to expose and reverse the reification of power.', example_ko_5 = '비판 이론은 권력의 물화를 폭로하고 뒤집으려 해요.' WHERE id = 'w_discussion_C2_28';

UPDATE words SET example_en_2 = 'His transcendental argument revealed the conditions of possible experience.', example_ko_2 = '그의 선험적 논증은 가능한 경험의 조건들을 드러냈어요.', example_en_3 = 'A transcendental critique examines what makes knowledge possible.', example_ko_3 = '선험적 비판은 지식을 가능하게 하는 것을 검토해요.', example_en_4 = 'She applied transcendental reasoning to the question of free will.', example_ko_4 = '그녀는 자유의지 문제에 선험적 추론을 적용했어요.', example_en_5 = 'Kant''s transcendental philosophy changed the way we think about knowledge.', example_ko_5 = '칸트의 선험적 철학은 우리가 지식에 대해 생각하는 방식을 바꿨어요.' WHERE id = 'w_discussion_C2_29';

UPDATE words SET example_en_2 = 'The elenchus forces the interlocutor to confront their own contradictions.', example_ko_2 = '엘렝코스는 대화 상대자가 자신의 모순과 마주하도록 강요해요.', example_en_3 = 'Socrates used the elenchus to show that accepted wisdom was hollow.', example_ko_3 = '소크라테스는 엘렝코스를 사용해 받아들여진 지혜가 공허하다는 것을 보여줬어요.', example_en_4 = 'The elenchus does not teach directly — it clears away false beliefs.', example_ko_4 = '엘렝코스는 직접 가르치지 않아요 — 그것은 거짓 믿음을 제거해요.', example_en_5 = 'She applied the elenchus in the seminar to reveal unexamined assumptions.', example_ko_5 = '그녀는 세미나에서 엘렝코스를 적용해 검토되지 않은 가정들을 드러냈어요.' WHERE id = 'w_discussion_C2_30';

UPDATE words SET example_en_2 = 'Paraconsistency allows reasoning to continue despite contradictions.', example_ko_2 = '준일관성은 모순에도 불구하고 추론이 계속될 수 있게 해요.', example_en_3 = 'A paraconsistency framework is useful for handling contradictory databases.', example_ko_3 = '준일관성 틀은 모순된 데이터베이스를 처리하는 데 유용해요.', example_en_4 = 'She argued for paraconsistency in normative ethical theory.', example_ko_4 = '그녀는 규범 윤리 이론에서 준일관성을 주장했어요.', example_en_5 = 'Paraconsistency challenges the classical logical principle that contradictions entail everything.', example_ko_5 = '준일관성은 모순이 모든 것을 함의한다는 고전 논리 원칙에 이의를 제기해요.' WHERE id = 'w_discussion_C2_31';

UPDATE words SET example_en_2 = 'The institution operates as a kind of social autopoiesis.', example_ko_2 = '그 기관은 일종의 사회적 자기 생산으로 작동해요.', example_en_3 = 'Luhmann applied autopoiesis to the theory of social systems.', example_ko_3 = '루만은 사회 시스템 이론에 자기 생산을 적용했어요.', example_en_4 = 'Autopoiesis describes how living systems maintain themselves through self-reference.', example_ko_4 = '자기 생산은 생명 시스템이 자기 참조를 통해 스스로를 유지하는 방법을 설명해요.', example_en_5 = 'The language of a community reproduces itself through autopoiesis.', example_ko_5 = '공동체의 언어는 자기 생산을 통해 스스로를 재생산해요.' WHERE id = 'w_discussion_C2_32';

UPDATE words SET example_en_2 = 'The apophatic tradition in theology defines the divine by negation.', example_ko_2 = '신학의 부정신학적 전통은 신성을 부정을 통해 정의해요.', example_en_3 = 'An apophatic approach says what something is not, rather than what it is.', example_ko_3 = '부정신학적 접근법은 무언가가 무엇인지보다 무엇이 아닌지를 말해요.', example_en_4 = 'She used an apophatic method to describe the limits of language.', example_ko_4 = '그녀는 부정신학적 방법을 사용해 언어의 한계를 묘사했어요.', example_en_5 = 'The apophatic silence speaks louder than any positive assertion.', example_ko_5 = '부정신학적 침묵은 어떤 긍정적 주장보다 더 크게 말해요.' WHERE id = 'w_discussion_C2_33';

UPDATE words SET example_en_2 = 'The metalinguistic function of language allows us to talk about language itself.', example_ko_2 = '언어의 메타언어학적 기능은 우리가 언어 자체에 대해 이야기할 수 있게 해요.', example_en_3 = 'Her metalinguistic analysis focused on how speakers frame their claims.', example_ko_3 = '그녀의 메타언어학적 분석은 화자들이 주장을 어떻게 구성하는지에 집중했어요.', example_en_4 = 'The debate shifted from the object level to a metalinguistic discussion.', example_ko_4 = '토론이 대상 수준에서 메타언어학적 논의로 이동했어요.', example_en_5 = 'A metalinguistic awareness helps speakers choose their words more precisely.', example_ko_5 = '메타언어학적 인식은 화자들이 더 정확하게 단어를 선택하는 데 도움이 돼요.' WHERE id = 'w_discussion_C2_34';

UPDATE words SET example_en_2 = 'The undecidability of certain propositions was proven by Gödel.', example_ko_2 = '특정 명제들의 결정 불가능성은 괴델에 의해 증명됐어요.', example_en_3 = 'Derrida located undecidability at the heart of all interpretation.', example_ko_3 = '데리다는 결정 불가능성을 모든 해석의 핵심에 위치시켰어요.', example_en_4 = 'In ethics, undecidability does not mean we should not choose.', example_ko_4 = '윤리에서 결정 불가능성은 우리가 선택해서는 안 된다는 것을 의미하지 않아요.', example_en_5 = 'The undecidability of the text forces the reader to take responsibility for meaning.', example_ko_5 = '텍스트의 결정 불가능성은 독자가 의미에 대한 책임을 지도록 강요해요.' WHERE id = 'w_discussion_C2_35';

